    // 3) savunma-sanayi-kaynakli-imalat
    blog_savunma_sanayi_kaynakli_imalat_title: 'Savunma Sanayii Kaynaklı İmalat: STANAG, MIL-STD ve Özel Çelikler | ArmaWeld',
    blog_savunma_sanayi_kaynakli_imalat_meta_desc: 'Savunma sanayii kaynaklı imalat: STANAG 4569 zırh seviyeleri, MIL-STD-1941, balistik çelik kaynağı ve kalite gereklilikleri.',
    blog_savunma_sanayi_kaynakli_imalat_og_title: 'Savunma Sanayii Kaynaklı İmalat: STANAG, MIL-STD ve Özel Çelikler',
