    blog_maliyet_optimizasyon_title: 'Kaynaklı İmalatta Maliyet Optimizasyonu | ArmaWeld',
    blog_maliyet_optimizasyon_meta_desc: 'Kaynaklı imalatta maliyet optimizasyonu: malzeme verimliliği, kaynak yöntem seçimi, otomasyon ve kalite maliyeti kontrolü.',
    blog_maliyet_optimizasyon_og_title: 'Kaynaklı İmalatta Maliyet Optimizasyonu',
